import{c as t,Q as a,j as o,m as i}from"./chunks/framework.CdiUUa3G.js";const u=JSON.parse('{"title":"ADR-029 ‚Äî Service worker via @vite-pwa/sveltekit","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-029.md","filePath":"adr/ADR-029.md"}'),s={name:"adr/ADR-029.md"};function r(n,e,l,c,d,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-029-‚Äî-service-worker-via-vite-pwa-sveltekit" tabindex="-1">ADR-029 ‚Äî Service worker via @vite-pwa/sveltekit <a class="header-anchor" href="#adr-029-‚Äî-service-worker-via-vite-pwa-sveltekit" aria-label="Permalink to &quot;ADR-029 ‚Äî Service worker via @vite-pwa/sveltekit&quot;">‚Äã</a></h1><blockquote><p>Status ¬∑ Accepted Date ¬∑ 2026-05-02 Closes ¬∑ Theme C.C1 from issue #18 (deferred in v0.1.10) TA anchor ¬∑ ¬ßcomponents/build ¬∑ ¬ßcomponents/static-deploy Related ADRs ¬∑ ADR-014 (GitHub Pages CI + preview), ADR-016 (build-time external assets), ADR-021 (docs site at /docs/), ADR-025 (a11y tier-1 contract)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">‚Äã</a></h2><p>v0.1.10 shipped a basic PWA manifest (<code>static/manifest.webmanifest</code>) but deferred the service worker. The deferral note in the v0.1.10 commit cited two concerns: (1) GitHub Pages base-path interaction with the SW scope, (2) the new dev-dep would need its own ADR.</p><p>This ADR addresses both. With the manifest in place users can already &quot;Add to Home Screen&quot; on Android; iOS additionally requires a registered SW for proper install behaviour. Offline-first behaviour for cold starts works through the browser&#39;s HTTP cache, but a SW lets us:</p><ol><li>Define explicit cache strategies per asset class (shell + textures cached aggressively; data files network-first with cache fallback so v0.1.x updates surface promptly).</li><li>Provide the offline-by-default UX iOS users expect from an installed app.</li><li>Pre-cache critical routes on install so first offline visit doesn&#39;t 404.</li></ol><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">‚Äã</a></h2><h3 id="plugin-choice-‚Äî-vite-pwa-sveltekit" tabindex="-1">Plugin choice ‚Äî <code>@vite-pwa/sveltekit</code> <a class="header-anchor" href="#plugin-choice-‚Äî-vite-pwa-sveltekit" aria-label="Permalink to &quot;Plugin choice ‚Äî `@vite-pwa/sveltekit`&quot;">‚Äã</a></h3><p>Use the official <code>@vite-pwa/sveltekit</code> integration (Vite ecosystem, maintained by the Vite PWA project). Adds a single devDependency. Generates the SW from a Workbox config in <code>vite.config.ts</code> and integrates with the existing <code>@sveltejs/adapter-static</code> build chain.</p><p><strong>Rejected:</strong> hand-rolled SW (more control but more maintenance; Workbox handles cache-busting, navigation fallback, and update-flow correctly out of the box).</p><h3 id="cache-strategy" tabindex="-1">Cache strategy <a class="header-anchor" href="#cache-strategy" aria-label="Permalink to &quot;Cache strategy&quot;">‚Äã</a></h3><ul><li><strong>Precache</strong> (cache-first, immutable): app shell HTML/JS/CSS, fonts (<code>static/fonts/*</code>), texture atlases (<code>static/textures/*</code>), agency logos (<code>static/logos/*.svg</code>), planet/sun/earth-object/moon-site images (everything under <code>static/images/</code>).</li><li><strong>Runtime cache</strong> (stale-while-revalidate): mission JSON files (<code>static/data/missions/**/*.json</code>) and i18n overlays. Users get the cached copy instantly while a fresh fetch updates the cache for next visit.</li><li><strong>Network-first</strong> (fall back to cache): the <code>static/data/mission-galleries.json</code> + sibling manifests. These rarely change but new fetch-assets runs may add entries.</li><li><strong>Excluded from cache</strong>: porkchop grid JSONs (<code>static/data/porkchop/*.json</code>) ‚Äî large (~110 KB each) and accessed only on the /plan screen; let the browser HTTP-cache them on demand.</li></ul><h3 id="base-path-handling" tabindex="-1">Base-path handling <a class="header-anchor" href="#base-path-handling" aria-label="Permalink to &quot;Base-path handling&quot;">‚Äã</a></h3><p>The SW scope must match the deployed base path (<code>/orrery/</code> on GitHub Pages, <code>/</code> on local preview). <code>@vite-pwa/sveltekit</code> reads <code>process.env.VITE_BASE</code> (already set by <code>svelte.config.js</code>) so the plugin&#39;s <code>manifest.scope</code> and <code>start_url</code> are computed correctly per-environment. Verified by the existing <code>svelte.config.js:17</code> pattern.</p><h3 id="install-prompt-ux" tabindex="-1">Install-prompt UX <a class="header-anchor" href="#install-prompt-ux" aria-label="Permalink to &quot;Install-prompt UX&quot;">‚Äã</a></h3><p>Show the install prompt only after the user has visited <strong>3 or more screens</strong>. This avoids the &quot;install this!&quot; pop-up on first paint that drives bounce. Visit counter held in <strong>runtime memory only</strong> (per CLAUDE.md &quot;do not use localStorage&quot;). Cleared on tab close ‚Äî acceptable since the SW itself persists across sessions.</p><p>Implementation: <code>src/routes/+layout.svelte</code> increments a counter on each route change; <code>beforeinstallprompt</code> event handler defers the call to <code>event.prompt()</code> until the counter ‚â• 3.</p><h3 id="ios-pwa-caveats" tabindex="-1">iOS PWA caveats <a class="header-anchor" href="#ios-pwa-caveats" aria-label="Permalink to &quot;iOS PWA caveats&quot;">‚Äã</a></h3><p>iOS Safari ignores <code>beforeinstallprompt</code>. iOS users get a manual &quot;Add to Home Screen&quot; via the share sheet. The manifest&#39;s <code>display: standalone</code> + <code>apple-mobile-web-app-capable</code> meta tag still produce the correct in-app shell. Documented in README under &quot;Install as app&quot;.</p><h3 id="ci-verification" tabindex="-1">CI verification <a class="header-anchor" href="#ci-verification" aria-label="Permalink to &quot;CI verification&quot;">‚Äã</a></h3><p>CI runs <code>npm run build</code> and verifies the SW file lands in <code>build/</code> (a single <code>grep -q service-worker.js build/</code> check added to <code>.github/workflows/ci.yml</code>). Lighthouse CI gate for PWA score deferred to a v0.1.12 follow-up since it needs a separate <code>lhci</code> config.</p><h3 id="update-flow" tabindex="-1">Update flow <a class="header-anchor" href="#update-flow" aria-label="Permalink to &quot;Update flow&quot;">‚Äã</a></h3><p>Users on a stale shell get a &quot;New version available ‚Äî refresh?&quot; toast when the SW detects a new build. Implementation: <code>vite-pwa/sveltekit</code>&#39;s built-in <code>useRegisterSW</code> composable, surfaced in <code>+layout.svelte</code>. Reduced-motion users get the same toast without the slide-in animation (gated by the global <code>prefers-reduced-motion: reduce</code> rule).</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">‚Äã</a></h2><p><code>@vite-pwa/sveltekit</code> is the path of least resistance: officially supported, maintained, integrates with adapter-static + dynamic base path, and handles Workbox config without hand-rolled boilerplate. The cache strategies match the natural data-vs-shell split already implicit in the repo structure (everything under <code>static/</code> is build-time-fixed; mission JSON evolves between releases).</p><p>The visit-counter deferral pattern matches the spirit of CLAUDE.md&#39;s &quot;no surprises&quot; rule ‚Äî install prompts are an interruption; deferring until the user has demonstrated engagement (3+ screens) lets the prompt feel earned.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">‚Äã</a></h2><ul><li><strong>Hand-rolled SW + manual cache management</strong> ‚Äî more flexibility but more maintenance. Rejected because Workbox already handles the 95% case correctly.</li><li><strong>Workbox CLI standalone</strong> ‚Äî ships an SW but needs a separate build step outside Vite. Rejected because <code>@vite-pwa/sveltekit</code> integrates with the existing pipeline.</li><li><strong>No SW, ship manifest only</strong> ‚Äî what v0.1.10 did. Works on Android but iOS install behaviour is degraded. Rejected because the additional install-friction on iOS hurts the &quot;browser-native, no app store&quot; promise.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">‚Äã</a></h2><p><strong>Positive:</strong></p><ul><li>Orrery becomes properly installable on iOS + Android with offline-first behaviour after first visit.</li><li>Cache strategies keep shell + assets fast while letting data updates surface.</li><li>Update toast gives users explicit control over when to pick up new builds.</li><li>Visit-counter deferral keeps the install prompt from being intrusive.</li></ul><p><strong>Negative:</strong></p><ul><li>New devDependency: <code>@vite-pwa/sveltekit</code> (~2 MB install size; pulls in <code>workbox-*</code> packages). Acceptable per ADR-016&#39;s external-asset budget.</li><li>SW debugging adds a small operational cost: stale caches require devtools &quot;Update on reload&quot; or unregister to test fresh.</li><li>GitHub Pages base-path edge cases need verification before tagging ‚Äî covered by the build-step <code>grep</code> check in CI.</li><li>iOS users still don&#39;t get <code>beforeinstallprompt</code>; their install path stays manual via the share sheet.</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">‚Äã</a></h2><ul><li><code>vite.config.ts</code> gains a <code>SvelteKitPWA</code> plugin block with <code>registerType: &#39;prompt&#39;</code>, <code>manifest: false</code> (manifest is already at <code>static/manifest.webmanifest</code>), and a <code>workbox</code> config defining <code>globPatterns</code> + <code>runtimeCaching</code>.</li><li><code>src/routes/+layout.svelte</code> gains a small <code>useRegisterSW</code>-driven update toast + visit-counter logic for <code>beforeinstallprompt</code>.</li><li><code>package.json</code> adds <code>@vite-pwa/sveltekit</code> to devDependencies.</li><li>README &quot;Install as app&quot; section explains both Android (auto-prompt) and iOS (share sheet) paths.</li></ul><p>Issue tracking: closes Theme C.C1 from #18. C2 (manual contrast toggle) and C3 (Lighthouse gate) follow in the same v0.1.12 milestone but are tracked separately in this plan.</p>',36)])])}const m=t(s,[["render",r]]);export{u as __pageData,m as default};
